content.text:
/* Reset fieldset browser defaults */
fieldset {
  border: 1px solid #d1d5db;
  border-radius: 8px;
  padding: 1rem 1.25rem;
  margin: 0 0 1rem;
}

legend {
  font-weight: 600;
  color: #374151;
  padding: 0 0.5rem;
}

/* Vertically stacked label + input */
.field {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
  margin-bottom: 1rem;
}

label {
  font-size: 0.875rem;
  font-weight: 500;
  color: #374151;
}

/* Visually hidden but screen-reader accessible */
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

/* Error state */
input[aria-invalid="true"] {
  border-color: #dc2626;
  outline-color: #dc2626;
}

.error {
  color: #dc2626;
  font-size: 0.75rem;
}
